98	function DesktopChatItem({
99	  chat, isActive, isRenaming, renameValue, indent = false,
100	  onSelect, onRenameChange, onRenameSubmit, onRenameCancel, onStartRename, onPin, onDelete,
101	}: DesktopChatItemProps) {
102	  const [hovered, setHovered] = useState(false);
103	  const showMenu = isActive || hovered;
104	
105	  return (
106	    <div
107	      onClick={() => { if (!isRenaming) onSelect(); }}
108	      onMouseEnter={() => setHovered(true)}
109	      onMouseLeave={() => setHovered(false)}
110	      style={{ position: 'relative' }}
111	      className={`flex items-center gap-2 ${indent ? 'py-1.5 pl-7 pr-8' : 'py-2 pl-2.5 pr-8'} rounded-lg cursor-pointer transition-all ${
112	        isActive ? 'bg-bronze/10 text-foreground' : 'text-muted-foreground hover:bg-muted/50 hover:text-foreground'
113	      }`}
114	    >
115	      <MessageSquare className={`w-${indent ? '3.5' : '4'} h-${indent ? '3.5' : '4'} flex-shrink-0 ${isActive ? 'text-bronze' : ''}`} />
116	
117	      {isRenaming ? (
118	        <input
119	          autoFocus
120	          value={renameValue}
121	          onChange={(e) => onRenameChange(e.target.value)}
122	          onKeyDown={(e) => {
123	            if (e.key === 'Enter') onRenameSubmit();
124	            if (e.key === 'Escape') onRenameCancel();
125	          }}
126	          onBlur={onRenameSubmit}
127	          onClick={(e) => e.stopPropagation()}
128	          className="flex-1 bg-transparent text-base md:text-sm outline-none border-b border-bronze/50 focus:border-bronze text-foreground min-w-0"
129	        />
130	      ) : (
131	        <span className="flex-1 min-w-0 text-sm truncate">{chat.title}</span>
132	      )}
133	
134	      <DropdownMenu>
135	        <DropdownMenuTrigger asChild onClick={(e) => e.stopPropagation()}>
136	          <button
137	            style={{
138	              position: 'absolute',
139	              right: '4px',
140	              top: '50%',
141	              transform: 'translateY(-50%)',
142	              opacity: showMenu ? 1 : 0.35,
143	              pointerEvents: 'auto',
144	              width: '24px',
145	              height: '24px',
146	              display: 'flex',
147	              alignItems: 'center',
148	              justifyContent: 'center',
149	              borderRadius: '4px',
150	              transition: 'opacity 0.15s',
151	              color: 'inherit',
152	            }}
153	          >
154	            <MoreVertical style={{ width: '14px', height: '14px' }} />
155	          </button>
156	        </DropdownMenuTrigger>
157	        <DropdownMenuContent align="end" className="w-44">
158	          <DropdownMenuItem
159	            onClick={(e) => { e.stopPropagation(); onPin(); }}
160	            className="gap-2 cursor-pointer"
161	          >
162	            {chat.pinned ? <PinOff className="w-3.5 h-3.5" /> : <Pin className="w-3.5 h-3.5" />}
163	            {chat.pinned ? 'Unpin' : 'Pin'}
164	          </DropdownMenuItem>
165	          <DropdownMenuItem
166	            onClick={(e) => { e.stopPropagation(); onStartRename(); }}
167	            className="gap-2 cursor-pointer"
168	          >
169	            <Pencil className="w-3.5 h-3.5" />
170	            Rename
171	          </DropdownMenuItem>
172	          <DropdownMenuSeparator />
173	          <DropdownMenuItem
174	            onClick={(e) => { e.stopPropagation(); onDelete(); }}
175	            className="gap-2 cursor-pointer text-destructive focus:text-destructive"
176	          >
177	            <Trash2 className="w-3.5 h-3.5" />
178	            Delete
179	          </DropdownMenuItem>
180	        </DropdownMenuContent>
181	      </DropdownMenu>
182	    </div>
183	  );
184	}
