235	
236	      <button
237	        onClick={(e) => { e.stopPropagation(); onLongPress(); }}
238	        className="flex items-center justify-center rounded-lg flex-shrink-0 text-muted-foreground/50 hover:text-muted-foreground hover:bg-muted/80 transition-all min-w-[44px] min-h-[44px]"
239	      >
240	        <MoreVertical className="w-3.5 h-3.5" />
241	      </button>
242	    </div>
243	  );
244	}
