246	function ThinkingIndicator() {
247	  return (
248	    <motion.div
249	      initial={{ opacity: 0, y: 8 }}
250	      animate={{ opacity: 1, y: 0 }}
251	      exit={{ opacity: 0, y: -4 }}
252	      transition={{ duration: 0.3 }}
253	      className="flex gap-3"
