302	function detectKiraIntent(text: string): string | null {
303	  const t = text.toLowerCase();
304	  if (/\b(canvas|contract|agreement)\b/.test(t) && /\b(create|draft|open|let'?s|ready|shall i|want me|here'?s|go ahead|click)\b/.test(t)) return 'open_contract';
305	  if (/\binvoice\b/.test(t) && /\b(create|draft|send|open|let'?s|ready|shall i|want me|here'?s|go ahead|click)\b/.test(t)) return 'open_invoice';
306	  return null;
307	}
