309	const Kira = () => {
310	  const { toast } = useToast();
311	  const { kiraActionsToday, kiraActionsLimit } = useSubscription();
312	  const isAtKiraLimit = kiraActionsToday >= kiraActionsLimit;
313	  const [userType, setUserType] = useState<'creator' | 'brand' | null>(null);
314	  const [userId, setUserId] = useState<string | null>(null);
315	  const [isLoading, setIsLoading] = useState(false);
316	  const [isStreaming, setIsStreaming] = useState(false);
317	  const [isLoadingHistory, setIsLoadingHistory] = useState(true);
318	  const messagesEndRef = useRef<HTMLDivElement>(null);
319	
320	  useEffect(() => {
321	    window.scrollTo(0, 0);
322	  }, []);
323	
324	  const creatorGreetings = [
325	    "Hey there! Let's build something great today",
326	    "The world needs your story — let's tell it better",
327	    "Ready to turn creative vision into action?",
328	    "Your next big collaboration starts here",
329	    "Let's craft content that truly resonates"
330	  ];
331	
332	  const brandGreetings = [
333	    "Hey there! Let's find the perfect storytellers for your brand",
334	    "Ready to connect with creators who share your vision?",
335	    "Your next winning campaign starts here",
336	    "Let's build partnerships that drive real impact",
337	    "Time to create something your audience will love"
338	  ];
339	
340	  const greetings = userType === 'brand' ? brandGreetings : creatorGreetings;
341	
342	  const getGreeting = () => {
343	    const lastChange = localStorage.getItem('kira-greeting-date');
344	    const storedIndex = localStorage.getItem('kira-greeting-index');
345	    const today = new Date().toDateString();
346	    
347	    if (lastChange !== today) {
348	      const currentIndex = storedIndex ? parseInt(storedIndex) : 0;
349	      const newIndex = (currentIndex + 1) % greetings.length;
350	      localStorage.setItem('kira-greeting-date', today);
351	      localStorage.setItem('kira-greeting-index', newIndex.toString());
352	      return greetings[newIndex];
353	    }
354	    
355	    const index = storedIndex ? parseInt(storedIndex) : 0;
356	    return greetings[index];
357	  };
358	
359	  const [currentGreeting, setCurrentGreeting] = useState(getGreeting());
360	  const [chatHistories, setChatHistories] = useState<ChatHistory[]>([]);
361	  const [projects, setProjects] = useState<Project[]>([]);
362	  const [activeChat, setActiveChat] = useState<string | null>(null);
363	  const [activeProjectId, setActiveProjectId] = useState<string | null>(null);
364	  const [messages, setMessages] = useState<Message[]>([]);
365	  const [input, setInput] = useState("");
366	  const [selectedFile, setSelectedFile] = useState<File | null>(null);
367	  const [sidebarCollapsed, setSidebarCollapsed] = useState(false);
368	  const [mobileSidebarOpen, setMobileSidebarOpen] = useState(false);
369	  const [searchQuery, setSearchQuery] = useState("");
370	  const imageInputRef = useRef<HTMLInputElement>(null);
371	  const textInputRef = useRef<HTMLInputElement>(null);
372	  const [selectedFileContent, setSelectedFileContent] = useState<string | null>(null);
373	  const [selectedFileType, setSelectedFileType] = useState<'image' | 'text' | null>(null);
374	  
375	  // View modes and dialogs
376	  const [viewMode, setViewMode] = useState<ViewMode>("chat");
377	  const [createProjectOpen, setCreateProjectOpen] = useState(false);
378	  const [selectedProject, setSelectedProject] = useState<Project | null>(null);
379	  const [projectDetailOpen, setProjectDetailOpen] = useState(false);
380	  const [isLoadingProjects, setIsLoadingProjects] = useState(true);
381	  const [contractDialogOpen, setContractDialogOpen] = useState(false);
382	  const [invoiceDialogOpen, setInvoiceDialogOpen] = useState(false);
383	  const [approveDialogOpen, setApproveDialogOpen] = useState(false);
384	  const [pendingAction, setPendingAction] = useState<string | null>(null);
385	  const [kiraContractContext, setKiraContractContext] = useState<Record<string, unknown> | null>(null);
386	  const [kiraInvoiceContext, setKiraInvoiceContext] = useState<Record<string, unknown> | null>(null);
387	
388	  const [chatToDelete, setChatToDelete] = useState<string | null>(null);
389	  const [memoryPanelOpen, setMemoryPanelOpen] = useState(false);
390	  const [renamingChatId, setRenamingChatId] = useState<string | null>(null);
391	  const [renameValue, setRenameValue] = useState("");
392	  const [mobileLongPressChat, setMobileLongPressChat] = useState<ChatHistory | null>(null);
393	  const longPressTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
394	  const streamBufferRef = useRef('');
395	  const animFrameRef = useRef<number | null>(null);
396	  const networkDoneRef = useRef(false);
397	  const chatContainerRef = useRef<HTMLDivElement>(null);
398	  useIOSKeyboardFit(chatContainerRef, () => messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' }));
399	
400	  // ── NEW: message interaction state ──
401	  const [editingMessageIdx, setEditingMessageIdx] = useState<number | null>(null);
402	  const [editingContent, setEditingContent] = useState("");
403	  const [copiedIdx, setCopiedIdx] = useState<number | null>(null);
404	  const [hoveredIdx, setHoveredIdx] = useState<number | null>(null);
405	
406	  useEffect(() => {
407	    const fetchUserData = async () => {
408	      const { data: { user } } = await supabase.auth.getUser();
409	      if (user) {
410	        setUserId(user.id);
411	        
412	        const { data: profile } = await supabase
413	          .from('profiles')
414	          .select('user_type')
415	          .eq('id', user.id)
416	          .single();
417	        
418	        if (profile) {
419	          setUserType(profile.user_type);
420	        }
421	
422	        const { data: conversations, error } = await supabase
423	          .from('kira_conversations')
424	          .select('*')
425	          .order('updated_at', { ascending: false });
426	
427	        if (!error && conversations) {
428	          setChatHistories(conversations.map(c => ({
429	            id: c.id,
430	            title: c.title,
431	            timestamp: new Date(c.updated_at),
432	            project_id: c.project_id,
433	            pinned: c.pinned ?? false,
434	          })));
435	          // Always land on a fresh new-chat state; user picks from sidebar to resume
436	        }
437	
438	        const { data: projectsData, error: projectsError } = await supabase
439	          .from('kira_projects')
440	          .select('*')
441	          .order('updated_at', { ascending: false });
442	
443	        if (!projectsError && projectsData) {
444	          setProjects(projectsData);
445	        }
446	        setIsLoadingProjects(false);
447	      }
448	      setIsLoadingHistory(false);
449	    };
450	
451	    fetchUserData();
452	  }, []);
453	
454	  useEffect(() => {
455	    const loadMessages = async () => {
456	      if (!activeChat) {
457	        setMessages([]);
458	        return;
459	      }
460	
461	      const { data: msgs, error } = await supabase
462	        .from('kira_messages')
463	        .select('*')
464	        .eq('conversation_id', activeChat)
465	        .order('created_at', { ascending: true });
466	
467	      if (!error && msgs) {
468	        setMessages(msgs.map(m => ({
469	          role: m.role as "user" | "assistant",
470	          content: m.content,
471	          file: m.file_name || undefined,
472	          timestamp: new Date(m.created_at),
473	        })));
474	      }
475	    };
476	
477	    loadMessages();
478	  }, [activeChat]);
479	
480	  useEffect(() => {
481	    if (userType) {
482	      const greeting = getGreeting();
483	      setCurrentGreeting(greeting);
484	    }
485	  }, [userType]);
486	
487	  // TopBar hamburger fires this — opens mobile sheet or toggles desktop collapse
488	  useEffect(() => {
489	    const handler = () => {
490	      if (window.innerWidth < 768) {
491	        setMobileSidebarOpen(true);
492	      } else {
493	        setSidebarCollapsed(prev => !prev);
494	      }
495	    };
496	    window.addEventListener("kira:toggle-sidebar", handler);
497	    return () => window.removeEventListener("kira:toggle-sidebar", handler);
498	  }, []);
499	
500	  useEffect(() => {
501	    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
502	  }, [messages]);
503	
504	  const saveMessage = async (conversationId: string, role: "user" | "assistant", content: string, fileName?: string) => {
505	    if (!content) {
506	      console.log("saveMessage skipped- content is empty");
507	      return;
508	    }
509	    const { error } = await supabase.from('kira_messages').insert({
510	      conversation_id: conversationId,
511	      role,
512	      content,
513	      file_name: fileName
514	    });
515	
516	    if (error) {
517	      console.log("saveMessage error:", JSON.stringify(error));
518	      console.log("values:", { conversationId, role, content, fileName });
519	    }
520	  };
521	
522	  const updateConversationTitle = async (conversationId: string, firstMessage: string) => {
523	    const title = firstMessage.slice(0, 50) + (firstMessage.length > 50 ? '...' : '');
524	    await supabase
525	      .from('kira_conversations')
526	      .update({ title, updated_at: new Date().toISOString() })
527	      .eq('id', conversationId);
528	    
529	    setChatHistories(prev => prev.map(c => 
530	      c.id === conversationId ? { ...c, title, timestamp: new Date() } : c
531	    ));
532	  };
533	
534	  const getActiveProject = () => {
535	    return projects.find(p => p.id === activeProjectId);
536	  };
537	
538	  // Character-reveal animation: drains streamBufferRef at ~6 chars/frame (~360 chars/sec)
539	  // so tokens appear smoothly instead of jumping in as large batches.
540	  useEffect(() => {
541	    if (!isStreaming) return;
542	    const CHARS_PER_FRAME = 6;
543	
544	    const tick = () => {
545	      if (streamBufferRef.current.length > 0) {
546	        const batch = streamBufferRef.current.slice(0, CHARS_PER_FRAME);
547	        streamBufferRef.current = streamBufferRef.current.slice(CHARS_PER_FRAME);
548	        setMessages(prev => {
549	          const updated = [...prev];
550	          const last = updated[updated.length - 1];
551	          if (last?.role === 'assistant') {
552	            updated[updated.length - 1] = { ...last, content: last.content + batch };
553	          }
554	          return updated;
555	        });
556	      }
557	
558	      if (streamBufferRef.current.length === 0 && networkDoneRef.current) {
559	        setIsStreaming(false);
560	        return;
561	      }
562	
563	      animFrameRef.current = requestAnimationFrame(tick);
564	    };
565	
566	    animFrameRef.current = requestAnimationFrame(tick);
567	    return () => {
568	      if (animFrameRef.current !== null) cancelAnimationFrame(animFrameRef.current);
569	    };
570	  }, [isStreaming]);
571	
572	  const streamKiraResponse = useCallback(async (
573	    userMessages: Message[],
574	    conversationId: string,
575	    attachContent?: string | null,
576	    attachType?: 'image' | 'text' | null,
577	    projectCtx?: { name: string; description: string | null; custom_instructions: string | null } | null,
578	  ) => {
579	    const lastUserContent = userMessages[userMessages.length - 1].content;
580	    const history = userMessages.slice(-7, -1).map(m => ({ role: m.role, content: m.content }));
581	
582	    const { data: { session } } = await supabase.auth.getSession();
583	    const token = session?.access_token;
584	    if (!token) throw new Error("Not authenticated");
585	
586	    const body: Record<string, unknown> = { prompt: lastUserContent, history, conversationId };
587	    if (attachContent && attachType) {
588	      body.fileContent = attachContent;
589	      body.fileType = attachType;
