33	// Username validation
34	const validateUsername = (username: string): string | null => {
35	  if (!username) return "Username is required";
36	  if (username.length < 3) return "Username must be at least 3 characters";
37	  if (username.length > 30) return "Username must be under 30 characters";
38	  if (/^[._-]/.test(username)) return "Username cannot start with a dot, underscore, or hyphen";
39	  if (/[._-]$/.test(username)) return "Username cannot end with a dot, underscore, or hyphen";
40	  if (/[._-]{2,}/.test(username)) return "Username cannot have consecutive special characters";
41	  if (!/^[a-zA-Z0-9._-]+$/.test(username)) return "Only letters, numbers, dots, underscores, and hyphens allowed";
42	  if (/^\d+$/.test(username)) return "Username cannot be only numbers";
43	  const reserved = ["admin", "support", "help", "about", "pricing", "auth", "dashboard", "api", "crevia", "kira", "settings", "profile", "signup", "login"];
44	  if (reserved.includes(username.toLowerCase())) return "This username is reserved";
45	  return null;
46	};
